mapper.sql:
FROM sys_role r
LEFT JOIN sys_config tts_config
    ON r.ttsId = tts_config.configId
   AND tts_config.configType = 'tts'
LEFT JOIN sys_config model_config
    ON r.modelId = model_config.configId
   AND model_config.configType = 'llm'
WHERE 1 = 1

    AND r.userId = #{userId}


    AND r.roleId = #{roleId}


    AND r.roleName LIKE CONCAT('%', #{roleName}, '%')


    AND r.isDefault = #{isDefault}


    AND r.state = #{state}
